function LFightSkill:GetSkillData()
	return self._skillData
end

function LFightSkill:Start(noSkillHud)
	self._startTime = nil
	self._isSkillFinished = false

	self._bSameSkillGroup = false
	self._bHideAtkObjHP = false
	if self._atkObj and self._atkObj:IsOnGridObj() then
		if self._skillData:IsSameSkillGroup() then
			---#570 skillEffGroup相同时，该组技能表现效果都隐藏血条和等级
			self._bHideAtkObjHP = true
			self._bSameSkillGroup = true
		elseif not self._skillData:IsNormal() and not (self._skillData:GetEffectType() == LFightConst.CALC_EFFECT_TYPE) then
			--#4066 释放技能时，当不是普攻和加血技能释放时，隐藏释放技能的对象血条和等级
			self._bHideAtkObjHP = true
		end
	end

	if not noSkillHud then
		self._showSkillHud = true
	end

	for k,v in ipairs(self._playEffList) do
		if v.effType == LSkillEffConst.PLAY_EFF_TREASURE then
			self:PrepareTreasure(v)
			self._isUpperLayer = true
			break
		end
	end

	self:OnPlayStart()
end

function LFightSkill:GeneratePlayState(index, refId, startTime, endTime,hurtDataIndex)
	local playState = {
		index = index,
		refId = refId,
		isPlay = true,
		startTime = startTime,
		endTime = endTime,
		isFinished = false,
		childFinished = false,
		childList = {} ,
		leftEffects = nil,

		hurtDataType = 0,
		hurtDataIndex = hurtDataIndex,
	}
	return playState
end

function LFightSkill:GenerateChildPlayState(effData, startTime, endTime)
	local playState = {
		effData = effData,
		isPlay = false,
		startTime = startTime,
		endTime = endTime,
		isFinished = false,
		--hurtDataType = 0,
		--hurtDataIndex = 1,
	}
	return playState
end
-----------------------------------------------------------------
function LFightSkill:PreloadPlayList()
	for k, v in ipairs(self._playEffList) do
		self:DoPreloadEff(v)
		if v.nextPlayList then
			for k1,v1 in ipairs(v.nextPlayList) do
				self:DoPreloadEff(v1)
			end
		end

	end
end
-----------------------------------------------------------------
function LFightSkill:CheckPlayList(time)
	--检测没有播放的时间有没有到，到了开始播放
	--已经播放的，检测自己的结束，和子效果的状态
	local playStateList = self._playStateList
	local bFinishAll = true
	for k, v in ipairs(self._playEffList) do
		--printInfoN("effrefid "..v.refId)
		local playState = playStateList[k]
		if not playState then
			bFinishAll = false
			if v.delayTime <= time then
				playState = self:GeneratePlayState(k, v.refId, time, v.playTime + time,v.effTargetIndex)
				playStateList[k] = playState
				if v.isEndSkill then
					if self._battleUnit and self._battleUnit:IsLastAtk() then
						self._battleUnit:BattleSkillEnd()
					end
				end
				self:DoPlayEff(v, playState)
			end
		elseif not playState.isFinished then
			local bChildFinished = playState.childFinished

			if not bChildFinished then
				bChildFinished = self:CheckChildPlayList(playState.childList,time)
				--if bChildFinished and playState.leftEffects then -- 防止遗漏的伤害没有播放
				--	self._battleUnit:DealShowHurt(playState.leftEffects)
				--end
			end

			playState.childFinished = bChildFinished

			local bTimeFinished = playState.endTime < time
			if bChildFinished and bTimeFinished then
				playState.isFinished = true
			else
				bFinishAll = false
			end
		end
	end

	return bFinishAll
end

--子弹技能跟随的播放列表
--childList 是通过GenerateChildPlaystate 建的结构
function LFightSkill:CheckChildPlayList(childList, time)
	if not childList or #childList == 0 then
		return true
	end
	local bFinishAll = true
	for m, child in ipairs(childList) do
		if not child.isPlay then
			if child.startTime <= time then
				child.isPlay = true
				self:DoPlayEff(child.effData, child)
			end
		elseif not child.isFinished then
			child.isFinished = child.endTime < time
		end
		if not child.isFinished then
			bFinishAll = false
		end
	end
	return bFinishAll
end

function LFightSkill:DoPlayEff(effData, playState)
	local effType = effData.effType


	--local time = self._battleUnit:GetTime()
	--printInfoN(string.format("DoPlayEff %s id %s",time,effData.refId))

	if effType == LSkillEffConst.PLAY_EFF_MOVE then
		self:ExecutePlayMove(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_ANI then
		self:ExecutePlayAni(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_EFFECT then
		self:ExecutePlayEffect(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_BULLET then
		self:ExecutePlayBullet(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_HIT_HUD or effType == LSkillEffConst.PLAY_EFF_HUD then
		self:ExecutePlayHitAndHud(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_SOUND then
		self:ExecutePlaySound(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_SHAKE then
		self:ExecutePlayShake(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_FADE then
		self:ExecuteMask(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_TOP_FADE then
		self:ExecuteTopMask(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_TREASURE then
	elseif effType == LSkillEffConst.PLAY_EFF_BUBBLE then
		self:ExecuteBubble(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_TREASURE_SKILL then
		self:ExecuteTreasureSkill(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_TREASURE_ICON then
		self:ExecuteTreasureIcon(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_FADE_EXTRA then
		self:ExecuteExtraFade(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_DRAWING then
		self:ExecuteDrawing(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_FADE_TOP_EXTRA then
		self:ExecuteTopMaskExtra(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_HIT_MOVE then
		self:ExecuteHitMove(effData,playState)
	elseif effType == LSkillEffConst.PLAY_EFF_SHOW_FOCUS then
		self:ExecuteShowFocus(effData,playState)
	elseif effType == LSkillEffConst.PALY_OBJ_TRANSFORM then
		self:ExecuteShowObjTransform(effData,playState)
	elseif effType == LSkillEffConst.PALY_OBJ_DIVINEWEAPONUI then
		self:ExecuteDivineWeaponUI(effData,playState)
	elseif effType == LSkillEffConst.PALY_OBJ_SORCERYCARD then
		self:ExecuteSorceryCard(effData,playState)
	end

	local soundName = effData.soundBattle
	if not string.isempty(soundName) then
		---@type LFightObject
		if self._atkObj and effData.needCheckSound then
			--- http://192.168.16.2:3002/issues/603
			soundName = self._atkObj:GetPlaySoundBattle(soundName,effData)
		end
		gLGameAudio:PlaySound(soundName)
	end
end

-----------------------------------------------------------------
--- Effect preload
-----------------------------------------------------------------
function LFightSkill:DoPreloadEff(effData)
	local effType = effData.effType
	if LSkillEffConst.PRELOAD_EFFECT_MAP[effType] then
		self:PreloadPlayEffect(effData)
	elseif effType == LSkillEffConst.PLAY_EFF_TREASURE then
		self:PrepareTreasure(effData)
	end
end

function LFightSkill:PreloadPlayEffect(effData)
	local effRes = effData.effRes --光效名字
	local resType = 1
	if effData.effType == LSkillEffConst.PLAY_EFF_DRAWING then
		resType = 2
	end

	local effectCtrl = self._battleUnit:GetEffectCtrl()
	local effTrans = self._battleUnit:GetEffectRootTrans()
	effectCtrl:PreloadEffectObject(effTrans,effRes,resType,nil,effData,self:GetTargetAtkObj())
end


