---播放移动
function LFightSkill:ExecutePlayMove(effData)
	local obj = self:GetTargetAtkObj()
	local moveTime = effData.playTime
	local effTarget = effData.effTarget
	local bulletTrack = effData.bulletTrack
	local offset = effData.effOffsetEnd
	local effOffsetStart = effData.effOffsetStart
	--local effTargetIndex = effData.effTargetIndex
	--local aId = obj:GetId()
	local tarPos = Vector3.zero
	local atkPos = obj:GetPosition()

	local tarObj = nil

	--获取一个符合的目标,最起码不是自己
	local skillHurtData = self._skillHurtDataList or {}

	local id = nil
	for k,v in ipairs(skillHurtData) do
		if id ~= nil then break end
		for k1,v1 in ipairs(v) do
			if id ~= nil then break end
			if v1.hitHurt then
				if self._isPosOnHook then
					local ht = v1.hitHurt.ht
					if ht and ht > 0 and not ignoreAllboHtMap[ht] then
						local tempTab = self._recordPosOnHookIdMap[v1.hitHurt.eId]
						if not tempTab or not tempTab[effData.effType] then
							id = v1.hitHurt.eId
							if not tempTab then
								tempTab = {}
								self._recordPosOnHookIdMap[id] = tempTab
							end
							tempTab[effData.effType] = true
							break
						end
					end
				else
					id = v1.hitHurt.eId
				end
			end
		end
	end

	if id then
		tarObj = self._battleUnit:GetHero(id)
	end

	local battleUnit = self._battleUnit
	if effTarget == LFightConst.PLAY_MOVE_TO_TARGET then
		tarPos = tarObj and tarObj:GetPosition() or self._battleUnit:GetMapCorePoint()
	elseif effTarget == LFightConst.PLAY_MOVE_TO_CENTER then
		tarPos = self._battleUnit:GetMapCorePoint()
	elseif effTarget == LFightConst.PLAY_MOVE_TO_BACK then
		tarPos = obj:GetGridPos()
	elseif effTarget == LFightConst.PLAY_MOVE_TO_SCREEN_OUTSIDE then
		local pos = obj:GetGridPos():Clone()
		local startX = LFightSkill.BORN_OFFSET
		tarPos = obj:GetSide() == 1 and Vector3(-startX,pos.y,0) or Vector3(startX,pos.y,0)

	elseif effTarget == LFightConst.EFFECT_TO_ENEMY_TEAM_COLUMN then
		--5=敌方目标所在列战场中心
		if not tarObj then
			LogError(string.format("战报中未找到目标 %s",id))
			return
		end
		local pos = tarObj:GetGridPos():Clone()
		tarPos = Vector3(0,pos.y,0)
	elseif effTarget == LFightConst.PLAY_SELF_CENTER then --己方九宫中心
		tarPos = battleUnit:GetFormationCenterPosition(obj:GetSide()):Clone()
	elseif effTarget == LFightConst.PLAY_OTHER_CENTER then --敌方九宫中心
		local side = battleUnit:GetOppositeSide(obj:GetSide())
		tarPos = battleUnit:GetFormationCenterPosition(side):Clone()
	elseif effTarget == LFightConst.PLAY_MOVE_SOLID then --固定偏移
		tarPos = atkPos
	elseif effTarget == LFightConst.PLAY_MOVE_ROW_CENTER then
		--9=目标排中心
		-- 选择下标最小的
		local selMinGrid
		local tempGrid = 1
		for k, v in ipairs(skillHurtData) do
			for k1,v1 in ipairs(v) do
				if v1.hitHurt then
					local tempTarObj = self._battleUnit:GetHero(v1.hitHurt.eId)
					tempGrid = tempTarObj:GetIndex()
					if not selMinGrid then
						selMinGrid = tempGrid
					elseif selMinGrid > tempGrid then
						selMinGrid = tempGrid
					end
				end
			end
		end
		if selMinGrid and selMinGrid > 0 then
			local side = battleUnit:GetOppositeSide(obj:GetSide())
			tarPos = battleUnit:GetRowCenterPos(side,selMinGrid)
		end
	end

	local isInSitu = effTarget == LFightConst.PLAY_MOVE_TO_INSITU
	local pos = Vector3(tarPos.x, tarPos.y + offset.y, 0)
	if not isInSitu then
		local side = obj:GetSide()
		local offsetX = nil
		if effTarget == LFightConst.PLAY_MOVE_SOLID then
			if side == LFightConst.ACTON_TEAM_A then
				offsetX =  offset.x
			else
				offsetX = - offset.x
			end
		else
			if side == LFightConst.ACTON_TEAM_A then
				offsetX = - offset.x
			else
				offsetX = offset.x
			end
		end

		pos.x = pos.x + offsetX
	end

	--动作名字
	local ani = effData.effRes
	if ani and not string.isempty(ani) then
		moveTime = effData.actionReset == 0 and moveTime or 0
		obj:PlayAni(ani, false, moveTime)
	end

	if isInSitu then
		obj:StartInSitu(effData)
		return
	end

	--obj:PlayRunAni(moveTime)
	if bulletTrack == LFightConst.BATTLE_LINEAR then
		obj:StartMove(pos, moveTime,true)
	elseif bulletTrack == LFightConst.BATTLE_CURVE_ONE then
		local topPosX = Mathf.Lerp(atkPos.x, pos.x,  2 / 3)
		local topPosY = atkPos.y + effOffsetStart.y
		local topPos = Vector3(topPosX,topPosY,0)
		obj:StartJumpTo(pos, topPos, moveTime, 0)
	elseif bulletTrack == LFightConst.BATTLE_CURVE_TWO then
		local startPos = pos + Vector3.New(0,10,0)
		obj:SetPosition(startPos)
		local direction = LFightConst.DIRECTION_LEFT
		if self._atkObj:GetActOn() == LFightConst.ACTON_TEAM_A then
			direction = LFightConst.DIRECTION_RIGHT
		end
		obj:SetDirection(direction)
		obj:StartMove(pos,moveTime)
		--printInfoN(string.format("move end pos x %s y %s",pos.x,pos.y))
	elseif bulletTrack == LFightConst.BATTLE_CURVE_THREE then
		obj:StartFade(moveTime)
	end

end

---播放动作
function LFightSkill:ExecutePlayAni(effData,playState)
	local obj = self:GetTargetAtkObj()
	--动作名字
	local ani = effData.effRes
	--动作时间
	local time = effData.playTime
	time = effData.actionReset == 0 and time or 0


	if not self._treasureObj then
		---# http://192.168.16.2:3002/issues/597
		--- SkillVfxRef中effType=2时，统一做成隐藏自己的血条（包括所有普攻、技能释放动作）
		obj:PlayBlockStickSHTween(time)
	end

	obj:PlayAni(ani, false, time)
	--if effData.bulletTrack == 1 then
	--	obj:ToOppositeDirection() --设置朝向
	--end
end


---播放光效
function LFightSkill:ExecutePlayEffect(effData,playState,extraData)
	local effRes = effData.effRes --光效名字

	local playNum = tonumber(effData.playNum)
	if playNum and playNum == 1 then
		FireEvent(EventNames.ON_LOAD_BATTLEWND_EFFECT,{
			preload = false,
			effId = effRes,
			resType = 1,
			effData = effData,
			state = 1,
		})
		return
	end

	local sceneDownEff = playNum and playNum == 2

	local playTime = effData.playTime --光效持续时间
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offset = effData.effOffsetStart --偏移
	local excursionIObject = effData.excursionIObject

	local dataList = {}
	local effTarget = effData.effTarget
	if playState.isTarBullet then
		local tempData = self:FormatEffectData(effData,playState)
		table.insert(dataList,tempData)
	else
		local hitHeroNum = 0
		local hitHeros = self._hitHeros or {}
		for k,v in pairs(hitHeros) do
			hitHeroNum = hitHeroNum + 1
		end
		local isHasMoreHitHero = hitHeroNum > 1

		if effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
			local effDataList = self:FormatEveryTargetEff(effData)
			if effDataList then
				if isHasMoreHitHero then
					for k,v in ipairs(effDataList) do
						local tempData,hasData = self:FormatEffectData(effData,v)
						if hasData then
							table.insert(dataList,tempData)
						end
					end
				else
					local selData = nil
					for i,v in ipairs(effDataList) do
						if v.tarId then
							selData = v
							break
						end
					end
					if selData then
						local tempData,hasData = self:FormatEffectData(effData,selData)
						if hasData then
							table.insert(dataList,tempData)
						end
					end
				end
			end
		else
			local tempData,hasData = self:FormatEffectData(effData,playState)
			if hasData then
				table.insert(dataList,tempData)
			end
		end
	end

	local isNeedScale = effTarget == LFightConst.EFFECT_TO_SELF or effTarget == LFightConst.EFFECT_TO_EVERY_TAR

	if self._isPosOnHook then
		local list = {}
		local effType = effData.effType
		for i,v in ipairs(dataList) do
			local tarId = v.tarId
			if not string.isempty(tarId) then
				local tempTab = self._recordPosOnHookIdMap[tarId]
				if not tempTab or not tempTab[effType] then
					if not tempTab then
						tempTab = {}
						self._recordPosOnHookIdMap[tarId] = tempTab
					end
					tempTab[effType] = true
					table.insert(list,v)
					break
				end
			end
		end
		if #list > 0 then
			dataList = list
		end
	end


	local targetObj = nil
	local boneName = effData.boneName
	if not string.isempty(boneName) then
		targetObj = self:GetTargetAtkObj()
	end

	local offsetX = offset.x
	local offsetY = offset.y
	local offsetZ = offset.z or 0

	local effectCtrl = self._battleUnit:GetEffectCtrl()
	for k, v in ipairs(dataList) do
		local pos = nil
		local dir = v.dir
		---根据子弹落点
		if excursionIObject == 1 and playState.bulletTarPos then
			pos = playState.bulletTarPos
			pos.z = 0
		else

			pos = v.pos
			local offset = nil
			if dir == LFightConst.DIRECTION_LEFT then
				offset = Vector3.New(-offsetX,offsetY,offsetZ)
			else
				offset = Vector3.New(offsetX,offsetY,offsetZ)
			end

			if v.isLocal then
				pos = offset
			else
				pos = v.pos + offset
			end
			pos.z = offsetZ
		end

		local rootTrans = v.trans

		local scale = 1
		if rootTrans == self._battleUnit:GetEffectRootTrans() then
			if isNeedScale then
				scale = self:GetScale()
				if scale > 1 then
					pos.y = pos.y * scale
				end
			end
		end

		local localPos = v.isLocal and pos or nil
		local effect = effectCtrl:MakeBattleSkillEffectObj(rootTrans, effRes, pos, dir, 0, playTime,dissipateTime)
		local isUpperLayer = self:IsUpperLayer(v.tarId)
		if sceneDownEff then
			isUpperLayer = false
		end
		local para = {
			isUpperLayer = isUpperLayer,
			scale = scale,
			localPos = localPos,
			targetObj = targetObj,
			boneName = boneName,
			extraData = extraData,
		}
		effect:SetEffectPara(para)

		effectCtrl:AddEffect(effect)
	end
end

---播放弹道
function LFightSkill:ExecutePlayBullet(effData, playState)
	local effTarget = effData.effTarget

	--printErrorN("play bullet refId "..effData.refId)
	if effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
		self:ExecuteTargetBullet(effData,playState)
	else
		self:ExecuteNormalBullet(effData,playState)
	end
end

function LFightSkill:ExecuteTargetBullet(effData,playState)
	local obj = self:GetTargetAtkObj()
	local effRes = effData.effRes --光效名字
	--local effTarget = effData.effTarget
	local moveSpeed = effData.moveSpeed * 0.01 -- 子弹飞行速度(配置表是像素这里要转换成米)
	local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offsetStart = effData.effOffsetStart --偏移
	local bulletCdTime = effData.bulletCdTime or 0 --多个子弹的延迟射出间隔
	local playNum = effData.playNum or {} --单个子弹分解次数
	local excursionIObject = effData.excursionIObject or 0
	local offsetEnd = effData.effOffsetEnd
	local effStartType = effData.effStartType or 1


	if moveSpeed < 0 then
		printErrorN(string.format("wrong speed %s",effData.refId))
		moveSpeed = 1
	end

	local dataList = {}
	local bulletDataList = self:FormatBulletData(effData)
	if bulletDataList then
		for k,v in ipairs(bulletDataList) do
			for k1,v1 in ipairs(v) do
				local tempData = self:FormatEffectData(effData,v1)
				local groupIndex = v1.groupIndex
				local groupDataList = dataList[groupIndex] or {}
				dataList[groupIndex] = groupDataList
				table.insert(groupDataList,tempData)
			end
		end
	end

	local effectCtrl = self._battleUnit:GetEffectCtrl()
	local atkDir = obj:GetDirection()
	local atkPos = obj:GetPosition()
	local atkSide = obj:GetSide()
	local effectRootTrans = self._battleUnit:GetEffectRootTrans()
    --
	--local startPos = nil
	----朝左
	--if atkDir == LFightConst.DIRECTION_LEFT then
	--	startPos = Vector3(atkPos.x - offsetStart.x, atkPos.y + offsetStart.y, 0)
	--else
	--	--朝右
	--	startPos = Vector3(atkPos.x + offsetStart.x, atkPos.y + offsetStart.y, 0)
	--end

	for k,v in ipairs(dataList) do

		local isShow = false  ---客户端多段飘血 只有一个子效果
		local curBulletCdTime = 0
		--子弹都是从自身位置创建，跟自身方向相同
		for k1,v1 in ipairs(v) do
			local bulletData = v1.bulletData
			if bulletData then
				local tarId = bulletData.tarId
				local tarObj = self._battleUnit:GetHero(tarId)
				local targetPos = tarObj:GetPosition():Clone()
				local defaultPos = self:GetEffStartPos(effStartType,atkSide,atkPos,targetPos)
				local startPos = nil
				if atkDir == LFightConst.DIRECTION_LEFT then
					--朝左
					startPos = Vector3(defaultPos.x - offsetStart.x, defaultPos.y + offsetStart.y, 0)
				else
					--朝右
					startPos = Vector3(defaultPos.x + offsetStart.x, defaultPos.y + offsetStart.y, 0)
				end


				local offset = Vector3.zero
				--受击的 和 攻击的朝向相反的
				if atkDir == LFightConst.DIRECTION_RIGHT then
					offset.x = - offsetEnd.x
				else
					offset.x =  offsetEnd.x
				end

				if excursionIObject == 1 then
					local randomNum = self._heroOffectPointList[math.random(1,5)]  -- 目标人物偏移值，策划没有设置effOffsetEnd的前提下，0.1-0.3的区间范围：脚底，躯干，头顶
					offset.y = randomNum
				else
					offset.y = offsetEnd.y
				end

				--弹道落点
				local endPos = v1.pos + offset
				endPos.z = 0

				--弹道落点
				local point = endPos:Clone()

				local scale = self:GetScale()
				if scale and scale > 1 then
					startPos.y = startPos.y * scale
				end

				--计算出时间
				local moveTime = (Vector3.Distance(startPos, endPos) / moveSpeed)

				local effect = effectCtrl:MakeBattleSkillEffectObj(effectRootTrans, effRes, startPos, atkDir, curBulletCdTime, moveTime, dissipateTime)
				effect:SetBullet(true, endPos, moveTime, bulletTrack,k1)
				local para =
				{
					isUpperLayer= self:IsUpperLayer(tarId),-- self._isUpperLayer,
					scale = scale
				}
				effect:SetEffectPara(para)
				effectCtrl:AddEffect(effect)

				moveTime = moveTime + curBulletCdTime


				local hurtDataType =bulletData.hurtDataType
				local hurtDataIndex = bulletData.hurtDataIndex

				if hurtDataType == 1 then --客户端表现多段
					bulletCdTime = k <= #playNum and playNum[k] or playNum[#playNum]
					-- 单个目标多个子弹的延迟射出间隔
					curBulletCdTime = curBulletCdTime + bulletCdTime
				elseif hurtDataType == 2 then
					-- 多个目标的子弹的延迟射出间隔
					curBulletCdTime = curBulletCdTime + bulletCdTime
				elseif hurtDataType == 3 then
					curBulletCdTime = 0
				end

				local tarId = bulletData.tarId
				local childList = playState.childList
				local nextPlayList = effData.nextPlayList
				if childList then
					local startTime = playState.startTime

					for k2,v2 in ipairs(nextPlayList) do
						if v2.effType == LSkillEffConst.PLAY_EFF_HIT_HUD or v2.effType == LSkillEffConst.PLAY_EFF_HUD then
							if not isShow then
								local childStartTime = startTime + moveTime + v2.delayTime
								local childEndTime = childStartTime + v2.playTime
								local childPlayState = self:GenerateChildPlayState(v2, childStartTime, childEndTime)
								childPlayState.isTarBullet = true
								childPlayState.tarId = tarId
								childPlayState.hurtDataType = hurtDataType
								childPlayState.hurtDataIndex = hurtDataIndex
								childPlayState.bulletTarPos = point
								childPlayState.groupIndex = k
								table.insert(childList, childPlayState)
							end

							if hurtDataType == 1 and not isShow then --客户端多段飘血,只剩生成一个飘血
								isShow = true
							end
						else
							local childStartTime = startTime + moveTime + v2.delayTime
							local childEndTime = childStartTime + v2.playTime
							local childPlayState = self:GenerateChildPlayState(v2, childStartTime, childEndTime)
							childPlayState.isTarBullet = true
							childPlayState.tarId = tarId
							childPlayState.bulletTarPos = offset
							table.insert(childList, childPlayState)
						end
					end
				end
			end
		end
	end
end

function LFightSkill:ExecuteNormalBullet(effData, playState)
	local obj = self:GetTargetAtkObj()
	local effRes = effData.effRes --光效名字
	--local effTarget = effData.effTarget
	local moveSpeed = effData.moveSpeed * 0.01 -- 子弹飞行速度(配置表是像素这里要转换成米)
	local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offsetStart = effData.effOffsetStart --偏移
	local bulletCdTime = effData.bulletCdTime or 0 --多个子弹的延迟射出间隔
	--local playNum = effData.playNum or {} --单个子弹分解次数
	local excursionIObject = effData.excursionIObject or 0
	local effStartType = effData.effStartType or 1


	local curBulletCdTime = 0

	if moveSpeed <= 0 then
		printErrorN(string.format("wrong speed %s",effData.refId))
		moveSpeed = 1
	end

	local offsetEnd = effData.effOffsetEnd
	local bulletTarPosList = {}

	local atkDir = obj:GetDirection()
	local atkPos = obj:GetPosition()
	local atkSide = obj:GetSide()

	local bulletData = self:FormatEffectData(effData)
	local dataList = {}

	table.insert(dataList,bulletData)

	local effectRootTrans = self._battleUnit:GetEffectRootTrans()
	--local effectPos
    --
	--if atkDir == LFightConst.DIRECTION_LEFT then
	--	--朝左
	--	effectPos = Vector3(atkPos.x - offsetStart.x, atkPos.y + offsetStart.y, 0)
	--else
	--	--朝右
	--	effectPos = Vector3(atkPos.x + offsetStart.x, atkPos.y + offsetStart.y, 0)
	--end

	local effectCtrl = self._battleUnit:GetEffectCtrl()

	--子弹都是从自身位置创建，跟自身方向相同
	local moveTimeList = {}
	local maxMoveTime = 0

	for k, v in ipairs(dataList) do

		local defaultPos = self:GetEffStartPos(effStartType,atkSide,atkPos)
		local effectPos = nil
		if atkDir == LFightConst.DIRECTION_LEFT then
			--朝左
			effectPos = Vector3(defaultPos.x - offsetStart.x, defaultPos.y + offsetStart.y, 0)
		else
			--朝右
			effectPos = Vector3(defaultPos.x + offsetStart.x, defaultPos.y + offsetStart.y, 0)
		end

		local pos = v.pos
		--受击的 和 攻击的朝向相反的
		if atkDir == LFightConst.DIRECTION_RIGHT then
			pos.x = pos.x - offsetEnd.x
		else
			pos.x = pos.x + offsetEnd.x
		end

		if excursionIObject == 1 then
			local randomNum = self._heroOffectPointList[math.random(1,5)]  -- 目标人物偏移值，策划没有设置effOffsetEnd的前提下，0.1-0.3的区间范围：脚底，躯干，头顶
			pos.y = pos.y + randomNum
		else
			pos.y = pos.y + offsetEnd.y
		end

		pos.z = 0

		-- 弹道落点列表
		local point = pos:Clone()
		bulletTarPosList[k] = point

		local scale = self:GetScale()
		if scale and scale > 1 then
			effectPos.y = effectPos.y * scale
		end

		--计算出时间
		local moveTime = (Vector3.Distance(effectPos, pos) / moveSpeed)

		local effect = effectCtrl:MakeBattleSkillEffectObj(effectRootTrans, effRes, effectPos, atkDir, curBulletCdTime, moveTime, dissipateTime)
		effect:SetBullet(true, pos, moveTime, bulletTrack,k)
		local para =
		{
			isUpperLayer= self:IsUpperLayer(v.tarId),-- self._isUpperLayer,
			scale = scale
		}
		effect:SetEffectPara(para)
		effectCtrl:AddEffect(effect)

		moveTime = moveTime + curBulletCdTime
		if moveTime > maxMoveTime then
			maxMoveTime = moveTime
		end

		table.insert(moveTimeList, moveTime)

		--if v.isSingleBulletMuti then
		--	bulletCdTime = k <= #playNum and playNum[k] or playNum[#playNum]
		--	-- 单个目标多个子弹的延迟射出间隔
		--	curBulletCdTime = curBulletCdTime + bulletCdTime
		--else
		-- 多个目标的子弹的延迟射出间隔
		curBulletCdTime = curBulletCdTime + bulletCdTime
		--end
	end

	local nextPlayList = effData.nextPlayList

	local childList = playState.childList
	if not childList then
		return
	end

	--不嵌套子列表
	local startTime = playState.startTime
	for k, v in ipairs(nextPlayList) do
		local childStartTime = startTime + maxMoveTime + v.delayTime
		local childPlayState = self:GenerateChildPlayState(v, childStartTime, childStartTime + v.playTime)
		table.insert(childList, childPlayState)
	end

end

function LFightSkill:GetEffStartPos(offsetType,selfSide,selfPos,targetPos)

	targetPos = targetPos or Vector3.zero

	local battleUnit = self._battleUnit
	local tempPos = selfPos
	if offsetType == LFightConst.EFFECT_TO_SELF then
		--1=自身
		tempPos = selfPos
	elseif offsetType == LFightConst.EFFECT_TO_EVERY_TAR then
		--2=针对指定单位
		tempPos = targetPos
	elseif offsetType == LFightConst.EFFECT_TO_TARGET_CENTER then
		--3=目标群体中心
		local actionHurtDataList = self._skillHurtDataList or {} --self:GetActionDataEffectByIndex(offsetTypeIndex) or {}
		local posTotal = Vector3(0, 0, 0)
		local posLen = 0
		for k, v in ipairs(actionHurtDataList) do
			for k1,v1 in ipairs(v) do
				if v1.hitHurt then
					local id = v1.hitHurt.eId
					local tarObj = self._battleUnit:GetHero(id)
					local tarPos = tarObj:GetPosition()
					posTotal.x = posTotal.x + tarPos.x
					posTotal.y = posTotal.y + tarPos.y
					posLen = posLen + 1
				end
			end
		end
		if posLen > 0 then
			posTotal.x = posTotal.x / posLen
			posTotal.y = posTotal.y / posLen
		end
		tempPos = posTotal
	elseif offsetType == LFightConst.EFFECT_TO_SELF_TEAM_CENTER then
		--4=我方九宫中心格
		tempPos = self._battleUnit:GetFormationCenterPosition(selfSide):Clone()
	elseif offsetType == LFightConst.EFFECT_TO_ENEMY_TEAM_CENTER then
		--5=敌方九宫中心格
		tempPos = battleUnit:GetFormationCenterPosition(battleUnit:GetOppositeSide(selfSide)):Clone()
	elseif offsetType == LFightConst.EFFECT_TO_OFF_SCREEN_DOWN then
		--6=屏幕外下方
		tempPos = battleUnit:GetFormationOffScreenDownPosition(battleUnit:GetOppositeSide(selfSide)):Clone()
	elseif offsetType == LFightConst.EFFECT_TO_ZERO then
		--7=原点
		tempPos = Vector3.zero
	elseif offsetType == LFightConst.EFFECT_TO_ROW_CENTER then
		--9=目标排中心
		local side = LFightConst.SIDE_TEAM_A
		local grid = 1
		local actionHurtDataList = self._skillHurtDataList or {}
		for k, v in ipairs(actionHurtDataList) do
			for k1,v1 in ipairs(v) do
				if v1.hitHurt then
					local id = v1.hitHurt.eId
					local tarObj = self._battleUnit:GetHero(id)
					side = tarObj:GetSide()
					grid = tarObj:GetIndex()
					break
				end
			end
		end
		tempPos = battleUnit:GetRowCenterPos(side,grid)
	end

	return tempPos
end

