---播放被击与飘字
function LFightSkill:ExecutePlayHitAndHud(effData,playState)
	local effType = effData.effType
	local bHit = effType == LSkillEffConst.PLAY_EFF_HIT_HUD
	if bHit then
		local isNormal = self._skillData:IsNormal() --普攻还是技能
		bHit = isNormal and LFightConst.PLAY_HIT_ACTION_NORMAL or LFightConst.PLAY_HIT_ACTION_SKILL
	else
		bHit = LFightConst.PLAY_HIT_ACTION_NONE
	end

	local actionHurtDataList = self:GetSkillHurtByType(playState.hurtDataType,playState.hurtDataIndex,playState.groupIndex)
	if not actionHurtDataList then return end

	if self._isPosOnHook then
		local index = playState.index
		local atkObj = self:GetTargetAtkObj()
		local atkId = atkObj:GetId()
		local list = {}
		local state = false
		local targetId
		for i,effect in ipairs(actionHurtDataList.list) do
			if atkId == effect.aId then
				local id = effect.eId
				local targetObj = self._battleUnit:GetHero(id)
				if targetObj and targetObj:GetIndex() == index and ignoreAllboHtMap[effect.ht] and not self._recordSpecialMap[id] then
					self._recordSpecialMap[id] = true
					table.insert(list,effect)

					local data = self._recordNoSkillHurtMap[id]
					if data and data.dead then
						table.insert(list,data)
					end
				else
					if not self._recordSpecialMap[id] then
						if targetId and targetId ~= id then break end
						local tempTab = self._recordPosOnHookIdMap[id]
						if not tempTab or not tempTab[effType] then
							if not tempTab then
								tempTab = {}
								self._recordPosOnHookIdMap[id] = tempTab
							end
							table.insert(list,effect)
							if not targetId then
								targetId = id
							end
							state = true
						end
					end
				end
			end
		end

		if #list > 0 then
			local tempTab = self._recordPosOnHookIdMap[targetId]
			if not tempTab then
				tempTab = {}
				self._recordPosOnHookIdMap[targetId] = tempTab
			end
			tempTab[effType] = true

			actionHurtDataList.list = list
		end
	end

	local effOffsetStart = effData.effOffsetStart
	local offset = Vector3(effOffsetStart.x,effOffsetStart.y, 0)
	self._battleUnit:DealShowHurt({actionHurtDataList}, bHit,effData.playNum,offset,self)
end

function LFightSkill:ExecuteMask(effData)
	local fade = self:GetFadeObj()
	local para = {
		parentRoot =self._battleUnit:GetFadeRoot(),
		startTime = self._battleUnit:GetTime(),
		playTime = effData.playTime, --光效持续时间
		dissipateTime = effData.dissipateTime, --光效消散时间
		alpha = tonumber(effData.playNum),
		layer = "EffectDown",
		order = -1,
	}
	fade:Create(para)
end

function LFightSkill:ExecuteTopMask(effData,playstate,callback)
	local fade = self:GetFadeObj()

	local para =
	{
		parentRoot =self._battleUnit:GetFadeRoot(),
		startTime = self._battleUnit:GetTime(),
		playTime = effData.playTime, --光效持续时间
		dissipateTime = effData.dissipateTime, --光效消散时间
		alpha = tonumber(effData.playNum),
		layer = "EffectDownUp",
		order = -1,
		type = LFightFade.TYPE_TWO,
		callback = callback
	}

	fade:Create(para)

end

function LFightSkill:GetFadeObj()
	if not self._fadeObjList then
		self._fadeObjList = {}
	end

	local fade = LFightFade:New()
	table.insert(self._fadeObjList,fade)

	return fade
end

function LFightSkill:ExecuteExtraFade(effData)
	self:ExecuteTopMask(effData,nil,function ()
		self:ChangeHitHeroLayer(2)
		local target = self:GetTargetAtkObj()
		if target then
			target:ResetRender()
		end
	end)

	self:ChangeHitHeroLayer(1)

	local target = self:GetTargetAtkObj()
	if target then
		target:ToUpperLayer()
	end
end

function LFightSkill:ExecuteTopMaskExtra(effData)
