	}

	fade:Create(para)
end

function LFightSkill:ExecuteDrawing(effData,playState)
	local effRes = effData.effRes --光效名字
	local playTime = effData.playTime --光效持续时间
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offset = effData.effOffsetStart --偏移
	local offsetType = effData.effStartType or 1
	local isUpperLayer = effData.battleHierarchy == 0

	local obj = self:GetTargetAtkObj()
	local atkPos = obj:GetPosition()
	local atkSide = obj:GetSide()
	local id= nil
	local skillHurtData = self._skillHurtDataList or {}
	for k,v in ipairs(skillHurtData) do
		for k1,v1 in ipairs(v) do
			if v1.hitHurt then
				id = v1.hitHurt.eId
				break
			end
		end
	end

	local targetPos=nil
	if id then
		local tarObj = self._battleUnit:GetHero(id)
		targetPos = tarObj:GetPosition()
	end
	local pos = self:GetEffStartPos(offsetType,atkSide,atkPos,targetPos)
	local actOffset = offset
	if atkSide== LFightConst.SIDE_TEAM_B then
		actOffset = Vector3.New(-offset.x,offset.y,0)
	end
	local effPos = actOffset + pos

	local effectCtrl = self._battleUnit:GetEffectCtrl()
	local rootTrans = self._battleUnit:GetEffectRootTrans()
	local effect = effectCtrl:MakeBattleSkillEffectObj(rootTrans, effRes, effPos, LFightConst.DIRECTION_LEFT, 0, playTime,dissipateTime,LFightEffect.SPINE)
	local para =
	{
		scale = 1,
		localPos = nil,
		isUpperLayer = isUpperLayer,
		onStartCall = function()
			self:HideAllBlood()
		end,
		onEndCall = function()
			self:RecoverBloodShow()
		end
	}
	effect:SetEffectPara(para)
	effectCtrl:AddEffect(effect)
end


function LFightSkill:ExecuteBubble(effData)
	local obj = self:GetTargetAtkObj()
	local str =LUtil.GetFaceStr(effData.talkTxt,32)
	local startTime = self._battleUnit:GetTime()
	local lastTime =effData.playTime + effData.dissipateTime
	local offset = Vector3.New(effData.effOffsetStart.x,effData.effOffsetStart.y,0)
	obj:ShowBubbleStick(str,lastTime,startTime,effData.effRes,offset)
end

