function LFightSkill:ExecuteTreasureIcon(effData)
	local effRes = effData.effRes --光效名字
	local playTime = effData.playTime --光效持续时间
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offset = effData.effOffsetStart --偏移

	local effectCtrl = self._battleUnit:GetEffectCtrl()
	local effTrans = self._battleUnit:GetEffectRootTrans()
	--local pos = Vector3.New(offset.x,offset.y,0)

	local heroData = self._atkObj:GetHeroData()
	local skillId = self._skillData:GetSkillRefId()
	local index = heroData:GetSkillIndex(skillId)
	local side = heroData:GetActOn()
