	pos.y = pos.y + offset.y

	local effect = effectCtrl:MakeBattleSkillEffectObj(effTrans, effRes, pos, LFightConst.DIRECTION_RIGHT, 0, playTime,dissipateTime)

	local para =
	{
		type = 2,
		isUpperLayer= self:IsUpperLayer(), -- self._isUpperLayer,
		scale = 1,
		skillId = skillId,
		skin = self._skillData:GetTreasureSkin(),
	}
	effect:SetEffectPara(para)
	effectCtrl:AddEffect(effect)
end

function LFightSkill:OnFadeRun(time)

	if not self._fadeObjList then
		return
	end

	local cnt = #self._fadeObjList
	for k=cnt,1,-1 do
		local obj = self._fadeObjList[k]
		if not obj:OnRun(time) then
			obj:Destroy()
			table.remove(self._fadeObjList,k)
		end
	end
end


function LFightSkill:FormatBulletData(effData)
	local obj = self:GetTargetAtkObj()
	if not obj then
		return
	end

	local dataList = {}
	local playNum = effData.playNum

	--2=每一个目标
	local skillHurtList = self._skillHurtDataList --技能伤害表现
	local skillEffId = self:GetSkillEffId()
	local vfxRefId = effData.refId
	local isMultiBullet,vfxIndex = gModelSkill:IsMultiBulletShow(skillEffId,vfxRefId) --多个攻击特效，同一目标多个伤害
	local clientMulti = not table.isempty(playNum) and #playNum > 0  --一个攻击特效，多段伤害飘字表现

	-- 特殊多段子弹类型
	if clientMulti then  ---客户端表现多段
		local groupIndex = 1   ---根据不同目标划分子弹组
		for k,v in ipairs(skillHurtList) do
			local id = nil
			for k1,v1 in ipairs(v) do
				if v1.hitHurt then
					id = v1.hitHurt.eId
					break
				end
			end

			local cnt = #playNum +1
			for i=1,cnt do
				local tempData =
				{
					tarId=id,
					groupIndex = groupIndex,
					hurtDataType = 1,--实际是一次飘字
					hurtDataIndex = i, --子弹序号
				}

				local groupDataList = dataList[groupIndex] or {}
				dataList[groupIndex] = groupDataList
				table.insert(groupDataList,tempData)
			end
			groupIndex = groupIndex + 1
		end
	elseif isMultiBullet then --根据伤害次数计算子弹数
		local groupIndex = 1
		for k,v in ipairs(skillHurtList) do
			local hurtData = v[vfxIndex]
			if hurtData then
				local targetId = hurtData.hitHurt.eId
				local tempData = {
					tarId=targetId,
					groupIndex = groupIndex,
					hurtDataType = 2,
					hurtDataIndex = vfxIndex, --子弹序号
				}
				local groupDataList = dataList[groupIndex] or {}
				dataList[groupIndex] = groupDataList
				table.insert(groupDataList,tempData)
			end
			groupIndex = groupIndex + 1
		end
	else
		for k,v in ipairs(skillHurtList) do
			for k1,v1 in ipairs(v) do
				local id = v1.hitHurt.eId
				local tempData =
				{
					tarId=id,
					groupIndex = k,
					hurtDataType = 3, --单独多次飘字
					hurtDataIndex = k1, --子弹序号
				}
				local groupDataList = dataList[k] or {}
				dataList[k] = groupDataList
				table.insert(groupDataList,tempData)
			end
		end
	end

	return dataList

end

function LFightSkill:FormatEveryTargetEff(effData)
	local obj = self:GetTargetAtkObj()
	if not obj then return end

	local skillHurtList = self._skillHurtDataList --技能伤害表现
	local dataList = {}
	local index = 1
	for k,v in ipairs(skillHurtList) do
		for k1,v1 in ipairs(v) do
			local tempData = {
				tarId = v1.hitHurt.eId,
				hurtDataType = 3, --单独多次飘字
				hurtDataIndex = index, --子弹序号
			}
			table.insert(dataList, tempData)
			index = index+1
		end
	end
	return dataList
end


function LFightSkill:FormatEffectData(effData,bulletData)
	local hasData = false
	local effectData = {}
	local obj = self:GetTargetAtkObj()
	if not obj then
		return effectData,hasData
	end

	hasData = true
	local effTarget = effData.effTarget --目标类型
	local atkDir = obj:GetDirection()
	local battleUnit = self._battleUnit
    if effTarget == LFightConst.EFFECT_TO_SELF then
        --1=自身
        local dpTrans = obj:GetDpObject():GetDisplayTrans()
        local pos = obj:GetPosition():Clone()
		local tarId = self._atkObj:GetId()
        effectData = { trans = dpTrans, pos = pos, dir = obj:GetDirection(),isLocal = true,tarId = tarId}
    elseif effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
        --2=针对指定单位
        if bulletData then
            local tarObj = battleUnit:GetHero(bulletData.tarId)
			hasData = tarObj ~= nil
			if hasData then
				local pos = tarObj:GetPosition():Clone()
				local tran = tarObj:GetDpObject():GetDisplayTrans()
				effectData =  { trans = tran, pos = pos, dir = tarObj:GetDirection(),bulletData = bulletData,isLocal = true,tarId = bulletData.tarId}
			end
        end
    elseif effTarget == LFightConst.EFFECT_TO_TARGET_CENTER then
        --3=目标群体中心
        local actionHurtDataList = self._skillHurtDataList or {} --self:GetActionDataEffectByIndex(effTargetIndex) or {}
        local posTotal = Vector3(0, 0, 0)
        local posLen = 0
        for k, v in ipairs(actionHurtDataList) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local id = v1.hitHurt.eId
                    local tarObj = battleUnit:GetHero(id)
					if tarObj then
						local tarPos = tarObj:GetPosition()
						posTotal.x = posTotal.x + tarPos.x
						posTotal.y = posTotal.y + tarPos.y
						posLen = posLen + 1
					end
                end
            end
        end
        if posLen > 0 then
            posTotal.x = posTotal.x / posLen
            posTotal.y = posTotal.y / posLen
        end
        local effTrans = battleUnit:GetEffectRootTrans()
        effectData ={ trans = effTrans, pos = posTotal, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_SELF_TEAM_CENTER then
        --4=我方九宫中心格
        local effTrans = battleUnit:GetEffectRootTrans()
        local pos = battleUnit:GetFormationCenterPosition(obj:GetSide()):Clone()
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_ENEMY_TEAM_CENTER then
        --5=敌方九宫中心格
        local effTrans = battleUnit:GetEffectRootTrans()
        local pos = battleUnit:GetFormationCenterPosition(battleUnit:GetOppositeSide(obj:GetSide())):Clone()
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_OFF_SCREEN_DOWN then
        --6=屏幕外下方
        local effTrans = battleUnit:GetEffectRootTrans()
        local pos = battleUnit:GetFormationOffScreenDownPosition(battleUnit:GetOppositeSide(obj:GetSide())):Clone()
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_ZERO then
        --7=原点
        local effTrans = battleUnit:GetEffectRootTrans()
        local pos = Vector3.zero
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_ROW_CENTER then
        --9=目标排中心
        local effTrans = battleUnit:GetEffectRootTrans()
        local side = LFightConst.SIDE_TEAM_A
        local grid = 1
        local actionHurtDataList = self._skillHurtDataList or {}
        for k, v in ipairs(actionHurtDataList) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local id = v1.hitHurt.eId
                    local tarObj = battleUnit:GetHero(id)
                    side = tarObj:GetSide()
                    grid = tarObj:GetIndex()
                    break
                end

            end
        end
        local pos = battleUnit:GetRowCenterPos(side,grid)
        effectData =  { trans = effTrans, pos = pos, dir = atkDir }
	elseif effTarget == LFightConst.EFFECT_TO_SELFNOMOVE then
		local pos = obj:GetPosition():Clone()
		local tarId = self._atkObj:GetId()
		effectData = { trans = obj:GetConstObjRoot(), pos = pos, dir = obj:GetDirection(),isLocal = true,tarId = tarId}
    else
        printErrorN2("技能动效",string.format("动效终点目标错误 %s",effTarget))
    end

	return effectData,hasData
end

function LFightSkill:ExecuteHitMove(effData,playState)
	if table.isempty(self._hitHeros)then
		return
	end

	local offset =Vector3.New(effData.effOffsetStart.x,effData.effOffsetStart.y,0)
	local time = effData.playTime
	for k,v in pairs(self._hitHeros) do
		local heroId = k
		local obj = self._battleUnit:GetHero(heroId)
		if obj then
			local tarPos = obj:GetPosition() + offset
			obj:StartMove(tarPos,time)
		end
	end
end

function LFightSkill:ExecuteShowFocus(effData,playState)
	local recordHurtId = {}

	local atkObj = self._atkObj
	local atkObjId = atkObj and atkObj:GetId()

	local effectCtrl = self._battleUnit:GetEffectCtrl()

	local actionHurtDataList = self._skillHurtDataList or {}
	for k, v in ipairs(actionHurtDataList) do
		for k1,v1 in ipairs(v) do
			if v1.beforeList and #v1.beforeList > 0 then
				for idx,val in ipairs(v1.beforeList) do
					if val.ht and val.ht == LFightConst.HURT_TYPE_DIVIDE_EQUALLY then
						local id = v1.hitHurt.eId
						---@type LFightObject
						local tarObj = self._battleUnit:GetHero(id)
						if tarObj then
							recordHurtId[id] = true
						end
					end
				end
			end
			if v1.hitHurt then
				local id = v1.hitHurt.eId
				---@type LFightObject
				local tarObj = self._battleUnit:GetHero(id)
				if tarObj then
					recordHurtId[id] = true
				end
			end
		end
	end

	--- 溅射目标
	local spurtingHitHeros = self._spurtingHitHeros or {}
	for i,v1 in ipairs(spurtingHitHeros) do
		if v1.hitHurt then
			local id = v1.hitHurt.eId
			---@type LFightObject
			local tarObj = self._battleUnit:GetHero(id)
			if tarObj then
				recordHurtId[id] = true
			end
		end
	end

	effectCtrl:HidePlayingEffects(recordHurtId,atkObjId)

	local recordDownMaskMap = {}
	local battleUnit = self._battleUnit
	if battleUnit then
		local battleObjList = battleUnit:GetObjectCtrl():GetObjectList() or {}
		local id
		for i,v in ipairs(battleObjList) do
			id = v:GetId()
			if id ~= atkObjId and not v:IsDead() then
				if not recordHurtId[id] then
					recordDownMaskMap[id] = {
						obj = v,
					}
					v:SetBattleObjState(0)
					v:ShowBuffEffect(false)
				end
			end
		end
	end

	local layer = "Object"
	local order = 1
	if effData.battleHierarchy == 1 then
		layer = "EffectDown"
	end

	local fade = self:GetFadeObj()
	local para = {
		parentRoot = self._battleUnit:GetFadeRoot(),
		startTime = self._battleUnit:GetTime(),
		playTime = effData.playTime, --光效持续时间
		dissipateTime = effData.dissipateTime, --光效消散时间
		alpha = tonumber(effData.playNum),
		layer = layer,
		order = order,
		type = LFightFade.TYPE_FOUR,
		callback = function()
			for k,v in pairs(recordDownMaskMap) do
				v.obj:SetBattleObjState(1)
				v.obj:ShowBuffEffect_1(true)
			end
			effectCtrl:ShowPlayingEffects()
		end
	}

	fade:Create(para)
end

function LFightSkill:ExecuteShowObjTransform(effData,playState)
	local obj = self:GetTargetAtkObj()
	--动作名字
	local ani = effData.effRes
	--动作时间
	local time = effData.playTime
	time = effData.actionReset == 0 and time or 0


	if not self._treasureObj then
		obj:PlayBlockStickSHTween(time)
	end
	obj:CheckIsHasChangeWaitCb()
	obj:PlayAni(ani, false, time)
end

function LFightSkill:ExecuteDivineWeaponUI(effData,playState)
	FireEvent(EventNames.ON_LOAD_DIVINEWEAPONUI,{
		effData = effData,
		playState = playState,
		obj = self._atkObj,
		battleSkill = self,
	})
end

function LFightSkill:ExecuteSorceryCard(effData,playState)
	local data
	local tarHero = self:GetTargetAtkObj()
	if tarHero and tarHero:IsOnGridObj() then
		if tarHero:HasSCard() then
			local extraData = effData.extraData
			if extraData and extraData.sorceryCardId == tarHero:GetCardRefId() then
				local scRefId = extraData.sorceryCardId
				local CardData = tarHero._sCardData
				local cardRef = gModelSorceryCard:GetSorceryCardRefByRefId(scRefId)
				data = {
					serData = {
						refId = scRefId,
						level = CardData.level,
						icon = cardRef.icon,
						name = ccLngText(cardRef.name),
					},
					rootPath = "sky/card_point/",
					type = LFightConst.BUFF_SPECIAL_1,
				}
			end
		end
	end
	self:ExecutePlayEffect(effData,playState,data)
end

function LFightSkill:CalcPlaySpurtingTime()

end

function LFightSkill:ExecutePlaySpurting(targetId)
	local spurtingHitHeros = self._spurtingHitHeros
	if not spurtingHitHeros or #spurtingHitHeros < 1 then return end

	local spurtingHeroList = {}
	for i,v in ipairs(spurtingHitHeros) do
		if targetId and targetId == v.hitHurt.eId then
			table.insert(spurtingHeroList,v.hitHurt)
		end
	end

	if #spurtingHeroList < 1 then return end

	local showBulletTime
	local showHitTime
	local delayTime
	local playHitEffTypeInfo = nil
	if self._skillData then
		playHitEffTypeInfo = self._skillData:GetPlayHitEffTypeInfo()
		if playHitEffTypeInfo then
			local hitEffectType = playHitEffTypeInfo.hitEffectType
			if hitEffectType == LSkillEffConst.HIT_EFFTYPE_SPURTING then
				if playHitEffTypeInfo.hitBulletEffData ~= nil then
					local bulletTime = self:_PlaySpurtingBullet(playHitEffTypeInfo.hitBulletEffData,spurtingHeroList)
					if bulletTime and bulletTime > 0 then
						if not showBulletTime then
							showBulletTime = bulletTime
						elseif showBulletTime < bulletTime then
							showBulletTime = bulletTime
						end
					end
				end
				if playHitEffTypeInfo.hitEffRefIdData ~= nil then
					local hitTime = self:_PlaySpurtingHitEff(playHitEffTypeInfo.hitEffRefIdData,spurtingHeroList,showBulletTime)
					if hitTime and hitTime > 0 then
						if not showHitTime then
							showHitTime = hitTime
						elseif hitTime > showHitTime then
							showHitTime = hitTime
						end
					end
				end
			end
		end
	end
	if showBulletTime and showBulletTime > 0 then
		return showBulletTime
	elseif showHitTime and showHitTime > 0 then
		return showHitTime
	end
	return 0
end

---@return LFightObject
function LFightSkill:_GetHitObj()
	---@type LFightObject
	local hurtObj = nil
	--- 伤害目标列表
	local skillHurtDataList = self._skillHurtDataList or {}
	for k, v in ipairs(skillHurtDataList) do
		for k1,v1 in ipairs(v) do
			if v1.hitHurt then
				local id = v1.hitHurt.eId
				---@type LFightObject
				local tarObj = self._battleUnit:GetHero(id)
				if tarObj then
					hurtObj = tarObj
					break
				end
			end
		end
	end
	return hurtObj
end

--- 子弹溅射
function LFightSkill:_PlaySpurtingBullet(effData,spurtingHeroList)
	if not spurtingHeroList or #spurtingHeroList < 1 then return end

	local battleUnit = self._battleUnit
	if not battleUnit then return end

	---@type LFightObject
	local hurtObj = self:_GetHitObj()
	if not hurtObj then return end

	---@type LDisplaySpine
	local dpSpine = hurtObj:GetDpObject()
	if not dpSpine then return end

	local effRes = effData.effRes --光效名字
	local moveSpeed = effData.moveSpeed * 0.01 -- 子弹飞行速度(配置表是像素这里要转换成米)
	local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offsetStart = effData.effOffsetStart --偏移
	local excursionIObject = effData.excursionIObject or 0
	local offsetEnd = effData.effOffsetEnd
	local effStartType = effData.effStartType or 1

	local effectRootTrans = battleUnit:GetEffectRootTrans()
	local effectCtrl = battleUnit:GetEffectCtrl()

	local time

	local atkDir = hurtObj:GetDirection()
	local hurtPosition = hurtObj:GetPosition():Clone()
	for i,v in ipairs(spurtingHeroList) do
		local tarId = v.eId
		---@type LFightObject
		local tarObj = battleUnit:GetHero(tarId)
		if tarObj then
			local tarPos = tarObj:GetPosition():Clone()
			local defaultPos = self:GetEffStartPos(effStartType,atkDir,hurtPosition,tarPos)
			local startPos = nil
			if atkDir == LFightConst.DIRECTION_LEFT then
				--朝左
				startPos = Vector3(defaultPos.x - offsetStart.x, defaultPos.y + offsetStart.y, 0)
			else
				--朝右
				startPos = Vector3(defaultPos.x + offsetStart.x, defaultPos.y + offsetStart.y, 0)
			end
			local offset = Vector3.zero
			--受击的 和 攻击的朝向相反的
			if atkDir == LFightConst.DIRECTION_RIGHT then
				offset.x = - offsetEnd.x
			else
				offset.x =  offsetEnd.x
			end

			if excursionIObject == 1 then
				-- 目标人物偏移值，策划没有设置effOffsetEnd的前提下，0.1-0.3的区间范围：脚底，躯干，头顶
				local randomNum = self._heroOffectPointList[math.random(1,5)]
				offset.y = randomNum
			else
				offset.y = offsetEnd.y
			end
			--弹道落点
			local endPos = tarPos + offset
			endPos.z = 0
			--弹道落点
			local point = endPos:Clone()

			--计算出时间
			local moveTime = Vector3.Distance(startPos, endPos) / moveSpeed

			if not time then
				time = moveTime
			elseif time > moveTime then
				time = moveTime
			end

			local effect = effectCtrl:MakeBattleSkillEffectObj(effectRootTrans, effRes, startPos, atkDir, 0, moveTime, dissipateTime)
			effect:SetBullet(true, endPos, moveTime, bulletTrack,i)
			local para = {
				isUpperLayer= self:IsUpperLayer(tarId),-- self._isUpperLayer,
				scale = self:GetScale(),
			}
			effect:SetEffectPara(para)
			effectCtrl:AddEffect(effect)
		end
		return time
	end
end

--- 子弹伤害
function LFightSkill:_PlaySpurtingHitEff(effData,actionHurtDataList,showBulletTime)
	showBulletTime =showBulletTime or 0
	local battleUnit = self._battleUnit
	if not battleUnit then return end

	---@type LFightObject
	local hurtObj = self:_GetHitObj()
	if not hurtObj then return end

	local effRes = effData.effRes --光效名字
	local playTime = effData.playTime --光效持续时间
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offset = effData.effOffsetStart --偏移
	local excursionIObject = effData.excursionIObject
	local showTime
	local offsetX = offset.x
	local offsetY = offset.y
	local offsetZ = offset.z or 0
	local effectCtrl = battleUnit:GetEffectCtrl()
	local effectRootTrans = battleUnit:GetEffectRootTrans()
	for k, v in ipairs(actionHurtDataList) do
		local tarId = v.eId
		---@type LFightObject
		local tarObj = battleUnit:GetHero(tarId)
		if tarObj then
			local tarPos = tarObj:GetPosition():Clone()
			local dir = tarObj:GetDirection()

			local pos = nil
			local tOffset = nil
			if dir == LFightConst.DIRECTION_LEFT then
				tOffset = Vector3.New(-offsetX,offsetY,offsetZ)
			else
				tOffset = Vector3.New(offsetX,offsetY,offsetZ)
			end
			tOffset.z = offsetZ
			pos = tarPos + tOffset

			local effect = effectCtrl:MakeBattleSkillEffectObj(effectRootTrans, effRes, pos, dir, showBulletTime, playTime,dissipateTime)
			local para = {
				isUpperLayer= self:IsUpperLayer(tarId),
				scale = self:GetScale(),
				localPos = tarPos,
				targetObj = hurtObj,
			}
			effect:SetEffectPara(para)
			effectCtrl:AddEffect(effect)

			if not showTime then
				showTime = playTime
			elseif playTime > showTime then
				showTime = playTime
			end
		end
	end
	return showTime
end


---根据下标 获取战报的出手伤害数据
---返回 [{HurtEffect},{BuffEffect},{TreatEffect}] 列表
