function LFightSkill:FormatShowHurtData(hurtList)
	if not hurtList then return end

	local hurtDataList = {
		list = {}
	}
	for k,v in ipairs(hurtList) do
		if v.beforeList then
			for k1,v1 in ipairs(v.beforeList) do
				table.insert(hurtDataList.list,v1)

				self:AddSpurtHurtData(hurtDataList.list,v1)
			end
		end

		table.insert(hurtDataList.list,v.hitHurt)

		self:AddSpurtHurtData(hurtDataList.list,v.hitHurt)

		if v.afterList then
			for k1,v1 in ipairs(v.afterList) do
				table.insert(hurtDataList.list,v1)

				self:AddSpurtHurtData(hurtDataList.list,v1)
			end
		end
	end

	return hurtDataList
end

function LFightSkill:AddSpurtHurtData(list,hurt)
	local spurtingList =hurt.spurtingList
	if spurtingList then
		for k,v in ipairs(spurtingList) do
			table.insert(list, v)
		end
	end
end

function LFightSkill:FormatSingleShowData(hurt)
	if not hurt then return end

	local hurtDataList ={list={}}
	if hurt.beforeList then
		for k,v in ipairs(hurt.beforeList) do
			table.insert(hurtDataList.list,v)
			self:AddSpurtHurtData(hurtDataList.list,v)
		end
	end

	table.insert(hurtDataList.list,hurt.hitHurt)

	self:AddSpurtHurtData(hurtDataList.list,hurt.hitHurt)

	if hurt.afterList then
		for k,v in ipairs(hurt.afterList) do
			table.insert(hurtDataList.list,v)
			self:AddSpurtHurtData(hurtDataList.list,v)
		end
	end

	return hurtDataList
end

--[[
	self._skillHurtDataList 结构

	{
		--保持结构一致，不破坏战报时序
		{
			beforeList,
			hitHurt, --战报伤害结构 "hitType": 1,
			afterList,
		},
		{
			beforeList,
			hitHurt,
			afterList,
		},
	},
	{

	}
]]
---
---(0,0) 一次性飘完
---(0,index) 取第一块伤害列表的下标伤害
---(1,nil) 	取第一块伤害 (客户端多次伤害，战报只有一个伤害数据),支持多个目标，按groupIndex取对应伤害数据
---(2,index) 取第一块伤害列表的下标伤害(单目标,多子弹，伤害数据集中在第一块数据中，按序号一一对应取伤害)，支持多个目标，按groupIndex取对应伤害数据
---(3,index) 取第index块伤害(多目标,多子弹，伤害数据按目标id单独列出，按序号一一对应取伤害)
---如有遗漏的战报数据，在ShowLastEff()中集中处理
function LFightSkill:GetSkillHurtByType(type,index,groupIndex)
	type = type or 0
	index = index or 0
	if type == 0 then
		if index ==0 then
			local totalList = {list={}}
			for k,v in pairs(self._skillHurtDataList) do
				local showList = self:FormatShowHurtData(v)
				if showList then
					for k1,v1 in ipairs(showList.list) do
						table.insert(totalList.list,v1)
					end
				end
			end
			self._tempSDataList = {}
			return totalList
		else
			self._tempSDataList[1] = nil
			local hurtDataList = self._skillHurtDataList[1]
			if hurtDataList then
				local hurtData = hurtDataList[index]
				local tempSData = self._tempSDataList[1]
				if tempSData and tempSData.dataList then
					tempSData.dataList[index] = nil
				end
				local resultList = self:FormatSingleShowData(hurtData)
				if self._playHudNum == index and self._playHudNum > 1 then
					for i,v in ipairs(hurtDataList) do
						if i > index then
							local tHurtData = hurtDataList[i]
							if tHurtData.afterList and #tHurtData.afterList > 0 then
								for idx,val in ipairs(tHurtData.afterList) do
									if val.dead then
										table.insert(resultList.list,val)
									end
								end
							end
						end
					end
					return resultList
				else
					return resultList
				end
			end
		end
	elseif type == 1 then
		self._tempSDataList[groupIndex] = nil
		local hurtList = self._skillHurtDataList[groupIndex]
		return self:FormatShowHurtData(hurtList)
	elseif type == 2 or type == 3 then
		local hurtDataList = self._skillHurtDataList[groupIndex]
		if not hurtDataList then return end
		local hurtData = hurtDataList[index]
		local tempSData = self._tempSDataList[groupIndex]
		if tempSData and tempSData.dataList then
			tempSData.dataList[index] = nil
		end
		return self:FormatSingleShowData(hurtData)

	--elseif type == 3 then
	--	self._tempSDataList[groupIndex] = nil
	--	local hurtDatalist = self._skillHurtDataList[groupIndex]
	--	if not hurtDatalist then
	--		return
	--	end
    --
	--	return self:FormatShowHurtData(hurtDatalist)
	end
end



---以hitType == 1 为节点划分伤害数据，防止顺序错乱
function LFightSkill:ParseActionEffectData()
	local effectList = self._actionData:GetEffectList()
	local skillHurtDataList = {}
	local normalHurtDataList ={}
	local tempSDataList ={}
	local hitHeros = {}
	local spurtingHitHeros = {}
	local recordNoSkillHurtMap = {}

	for k,v in ipairs(effectList) do
		local normalList = {}
		local tempIndex = 1
		for k1,v1 in ipairs(v) do   --查询技能表现需要的伤害数据
			local isSkillHurt = false
			local skillHurtList = {}
			local tempSList = {}
			local hasHitType = false
			local index = 1
			for k2,v2 in ipairs(v1.list) do
				isSkillHurt = v2.hitType == 1
				if isSkillHurt then
					hitHeros[v2.eId] = true
					local data = {
						beforeList = normalList,
						hitHurt = v2,
					}
					table.insert(skillHurtList,data)
					table.insert(tempSList,{index = index,data = data}) --初始数据镜像
					index = index + 1
					normalList ={}
					hasHitType = true
				else
					if v2.dead then
						recordNoSkillHurtMap[v2.eId] = v2
					end
					table.insert(normalList,v2)
				end
				--- 溅射英雄记录
				if v2.spurtingList and #v2.spurtingList > 0 then
					for k3,v3 in ipairs(v2.spurtingList) do
						isSkillHurt = v3.hitType == 1
						if not isSkillHurt then
							--- 溅射加成需要显示角色
							if v3.ht and v3.ht == LFightConst.HURT_TYPE_SPUTTERING then
								isSkillHurt = true
							end
						end
						if isSkillHurt then
							local data = {
								beforeList = normalList,
								hitHurt = v3,
							}
							table.insert(spurtingHitHeros,data)
						end
					end
				end
			end
			if #normalList > 0 then
				local last = skillHurtList[#skillHurtList]
				if last then
					for idx,val in ipairs(normalList) do
						recordNoSkillHurtMap[val.eId] = nil
					end
					last.afterList = normalList
					normalList = {}
				end
			end
			if #skillHurtList > 0 then
				table.insert(skillHurtDataList,skillHurtList)
				table.insert(tempSDataList,{index = tempIndex,dataList = tempSList})
				tempIndex = tempIndex + 1
			end
		end
		if #normalList>0 then
			table.insert(normalHurtDataList,normalList)
		end
	end

	self._skillHurtDataList = skillHurtDataList
	self._normalHurtDataList = normalHurtDataList
	self._spurtingHitHeros = spurtingHitHeros

	self._recordNoSkillHurtMap = recordNoSkillHurtMap

	self._tempSDataList = tempSDataList

	self._hitHeros = hitHeros
end

function LFightSkill:ShowLastEff()

	local dataList ={}
	if self._tempSDataList then
		for k,v in pairs(self._tempSDataList) do
			table.insert(dataList,v)
		end
		table.sort(dataList,function (a,b)
			return a.index<b.index
		end)

		local tempList ={}
		for k,v in ipairs(dataList) do
			local tempTempList = {}
			for k1,v1 in pairs(v.dataList) do
				table.insert(tempTempList,v1)
			end

			table.sort(tempTempList,function (a,b)
				return a.index < b.index
			end)

			local list = {}
			for k1,v1 in ipairs(tempTempList) do
				table.insert(list,v1.data)
			end

			local data = self:FormatShowHurtData(list)
			table.insert(tempList,data)
		end

		if #tempList>0 then
			self._battleUnit:DealShowHurt(tempList, LFightConst.PLAY_HIT_ACTION_NONE,nil,nil,self)
		end
	end


	local normalList = {}
	for k,v in ipairs(self._normalHurtDataList) do
		local data ={list={}}
		for k1,v1 in ipairs(v) do
			table.insert(data.list,v1)
			self:AddSpurtHurtData(data.list,v1)
		end

		table.insert(normalList,data)
	end

	if #normalList>0 then
		self._battleUnit:DealShowHurt(normalList, LFightConst.PLAY_HIT_ACTION_NONE,nil)
	end
end


