---技能名字HUD
function LFightSkill:CreateSkillHUD()
	if not self._showSkillHud then
		return
	end

	self._showSkillHud = false

	local isNormal = self._skillData:IsNormal()
	if isNormal then
		return
	end

	--local skillNameImage = self._skillData:GetSkillNameImage()
	--if string.isempty(skillNameImage) then
	--	return
	--end
	local obj = self._atkObj
	if not obj then
		return
	end

	--local objType = obj:GetObjectType()
	local pos = nil
	local changeType = nil
	local skillId = self._skillData:GetSkillRefId()
	if obj:IsOnGridObj() then
		--local tarPos = obj:GetTopNodePos()
		local tarPos = obj:GetPosition()--技能飘字改成从腿部出现
		pos = tarPos and tarPos:Clone() or Vector3.zero
		changeType = LFightConst.HURT_TYPE_SKILL
		--elseif objType == LFightConst.OBJ_TREASURE then
		--	pos = Vector3.New(0,3,0)
		--	changeType = LFightConst.HURT_TREA
	else
		return
	end

	--技能飘字从腿部出现, 左边从左到右，右边从右到左
	local anim = obj:GetSide() == LFightConst.SIDE_TEAM_A and LFightConst.HUD_ANIM_LEFT_TO_RIGHT or LFightConst.HUD_ANIM_RIGHT_TO_LEFT
	local time = self._battleUnit:GetTime()
	local hunData = {
		pos = pos,
		time = time,
		changeType = changeType,
		playNum ={},
		skillId = skillId,
		animation = anim,
	}
	obj:ShowSkillNameHud(hunData,time)
end


------------------------------------------------------------------
function LFightSkill:OnRun(time)
	if self._isDestroy then
		return false
	end

	if self._isSkillFinished then
		return false
	end

	local isOk = self:OnTreasureRun(time)
	if not isOk then
		printInfoN("cur time "..time)
		return true
	end

	if self:CheckWaitSummon() then
		return true
	end

	if not self._startTime then
		self._startTime = time
	end

	if self._showSkillHud then
		self:CreateSkillHUD()
	end

	self:OnFadeRun(time)

	if not self:CheckPlayList(time - self._startTime) then
		return true
	end


	--printInfoN("show last eff")
	self:ShowLastEff()

	self._isSkillFinished = true
	return false
end

function LFightSkill:GetSkillId()
	return self._skillData:GetSkillRefId()
end

function LFightSkill:GetSkillEffId()
	return self._skillData:GetSkillEffId()
end

function LFightSkill:GetTargetTran(id)
	local obj = self._battleUnit:GetHero(id)
	if not obj then
		return nil
	end
	local dpObj = obj:GetDpObject()
	if not dpObj then
		return nil
	end
	local tran = dpObj:GetDisplayTrans()
	return tran
end

function LFightSkill:GetTargetTranPos(id)
	local obj = self._battleUnit:GetHero(id)
	if not obj then
		return Vector3.zero
	end
	local tarPos = obj:GetPosition()
	tarPos = tarPos:Clone()
	return tarPos
end

function LFightSkill:GetTargetDirection(id)
	local obj = self._battleUnit:GetHero(id)
	if not obj then
		return LFightConst.DIRECTION_RIGHT

	end
	return obj:GetDirection()

end

function LFightSkill:GetTargetAtkObj()
	if self._treasureObj then
		return self._treasureObj
	else
		return self._atkObj
	end

end

function LFightSkill:PrepareTreasure(effData)
	if self._treasureObj then
		return
	end
	local side = self._atkObj:GetSide()
	local pos = self._battleUnit:GetFormationCenterPosition(side):Clone()
	local startX = LFightSkill.BORN_OFFSET
	pos = Vector3.New(-startX,pos.y,pos.z)
	if side == LFightConst.ACTON_TEAM_B then
		pos = Vector3.New(startX,pos.y,pos.z)
	end
	local treaCtrl = self._battleUnit:GetTreasureObjCtrl()
	local heroId = self._atkObj:GetId()
	self._treasureObj = treaCtrl:LoadObj(heroId,effData)
	self._treasureObj:SetPara({side = side,pos = pos})

end

function LFightSkill:OnTreasureRun(time)
	if not self._treasureObj then
		return true
	end

	if self._treasureObj:IsObjReady() then
		self._treasureObj:OnRun(time)
		return true
	end
end

function LFightSkill:CheckWaitSummon()
	if self._atkObj then
		local isReady = self._atkObj:IsObjReady()
		if not isReady then
			return true
		end
	end
end

function LFightSkill:OnPlayEnd()
	--if self._fade then
	--	self._fade:Destroy()
	--	self._fade = nil
	--end

	if self._fadeObjList then
		for k,v in pairs(self._fadeObjList) do
			v:Destroy()
		end
		self._fadeObjList=nil
	end

	local objectType = self._atkObj:GetObjectType()
	if objectType == LFightConst.OBJ_TREASURE then
		local side = self._atkObj:GetSide()
		local objList = self._battleUnit:GetObjectCtrl():GetObjectList(side)
		for k,v in pairs(objList) do
			v:ResetRender()
			v:ReleaseHideKey("treasure")
		end

		self:ChangeHitHeroLayer(2)


		local heroData = self._atkObj:GetHeroData()
		local skillId = self._skillData:GetSkillRefId()
		heroData:OnTreasureSkillEnd(skillId)
		self._atkObj:ResetAlpha()

		if self._treasureObj then
			self._treasureObj:SetPosition(Vector3.New(6,0,0))
			self._treasureObj:ResetAlpha()
		end
	elseif objectType == LFightConst.OBJ_DIVINEWEAPON then
		--- 战斗圣武：先写这里，后续在调用
		local heroData = self._atkObj:GetHeroData()
		if heroData then
			local skillId = self._skillData:GetSkillRefId()
			if skillId and skillId > 0 then
				heroData:OnDivineWeaponSkillEnd(skillId)
				heroData:GenDivineWeaponCd(skillId,true)
			end
		end
	else
		self._atkObj:OnSkillEnd()
		if self._bResetBlock then
			--- 需要重新显示血条
			self._atkObj:ReleaseHideKey("skillUse")
		end
	end

end

function LFightSkill:OnPlayStart()
	local objectType = self._atkObj:GetObjectType()
	local side = self._atkObj:GetSide()
	if objectType == LFightConst.OBJ_TREASURE then
		local treaObj = self:GetTargetAtkObj()
		treaObj:SetRenderOrder(LFightConst.TOP_ORDER)

		self:ChangeHitHeroLayer(1)

		local objList = self._battleUnit:GetObjectCtrl():GetObjectList(side)
		for k,v in pairs(objList) do
			local id = v:GetId()
			if not self._hitHeros[id] then
				--v:HideBlood()
				v:SetHideBloodKey("treasure")
			end
		end
	elseif objectType == LFightConst.OBJ_DIVINEWEAPON then
		--- 战斗圣武：先写这里，后续在调用
		local heroData = self._atkObj:GetHeroData()
		if heroData then
			local skillId = self._skillData:GetSkillRefId()
			if skillId and skillId > 0 then
				heroData:OnDivineWeaponSkillStart(skillId)
			end
		end
	else
		self._atkObj:SetRenderOrder(LFightConst.TOP_ORDER)
		if self._bHideAtkObjHP then
			--self._atkObj:HideBlood()
			self._atkObj:SetHideBloodKey("skillUse")
			self._atkObj:ShowBuffEffect(false)
		end
		self._atkObj:SetIsSameSkillGroup(self._bSameSkillGroup)
		self._atkObj:OnSkillStart()
	end
end


function LFightSkill:GetScale()
	if self._atkObj then
		return self._atkObj:GetObjScale() or 1
	end
	return self._scale or 1
end

function LFightSkill:ChangeHitHeroLayer(layerType)
	if not self._hitHeros then
		return
	end
	for k,v in pairs(self._hitHeros) do
		local heroId = k
		local obj = self._battleUnit:GetHero(heroId)
		if obj then
			if layerType == 1 then
				obj:ToUpperLayer()
			elseif layerType == 2 then
				obj:ResetRender()
			end
		end
	end
end

function LFightSkill:HideAllBlood()
	local objCtrl = self._battleUnit:GetObjectCtrl()
	local objList = objCtrl:GetObjectList() or {}
	for k,v in ipairs(objList) do
		if v:IsNormalObj() then
			v:SetHideBloodKey("drawing")
		end
	end
end

function LFightSkill:RecoverBloodShow()
	local objCtrl = self._battleUnit:GetObjectCtrl()
	local objList = objCtrl:GetObjectList() or {}
	for k,v in ipairs(objList) do
		if v:IsNormalObj() then
			v:ReleaseHideKey("drawing")
		end
	end
end

function LFightSkill:IsUpperLayer(heroId)
	if self._isUpperLayer then
		return true
	end
	if not heroId then
		return
	end
	local obj = self._battleUnit:GetHero(heroId)
	if obj then
		return obj:IsUpperLayer()
	end
end

function LFightSkill:NeedResetBlock(bReset)
	---#570 skillEffGroup相同时，该组技能表现效果都隐藏血条和等级
	self._bResetBlock = bReset
end

function LFightSkill:UpdateHerosBgState()
	if self._hitHeros then
		for k,v in pairs(self._hitHeros) do
			local heroId = k
			local obj = self._battleUnit:GetHero(heroId)
			if obj then
				obj:SetHeroBg_Hit()
			end
		end
	end
	if self._atkObj then
		self._atkObj:SetHeroBg_Attack()
	end
end

function LFightSkill:ResetHerosBgState()
	if self._hitHeros then
		for k,v in pairs(self._hitHeros) do
			local heroId = k
			local obj = self._battleUnit:GetHero(heroId)
			if obj then
				obj:SetHeroBg_Normal()
			end
		end
	end
	if self._atkObj then
		self._atkObj:SetHeroBg_Normal()
	end
end

-----------------------------------------------------------------
function LFightSkill:IsDestroy()
	return self._isDestroy
end

function LFightSkill:Destroy()
	--print("LFightSkill:Destroy()")


	self:OnPlayEnd()

	FireEvent(EventNames.CHANGE_BATTLE_WND_SHOW,true)
	table.removeall(self)
	self._isDestroy = true
end

return LFightSkill
